UPDATE d_pay_order_event
SET event_status = #{retryingStatus},
    next_retry_time = #{now},
    edit_time = #{now}
WHERE event_status = #{processingStatus}
  AND edit_time <= #{deadline}
  AND status = 1

UPDATE d_pay_order_event
SET event_status = #{succeededStatus},
    last_error = NULL,
    edit_time = #{now}
WHERE event_key = #{eventKey}
  AND status = 1
